import React from "react";

import { CheckIcon, ErrorIcon, InfoIcon } from "@steez-ui/icons";

import styles from "./StatusMessage.module.css";

export interface StatusMessageProps {
  message: string;
  type: "success" | "error" | "info";
}

export function StatusMessage({ message, type }: StatusMessageProps) {
  return (
    <div
      className={`${styles.message} ${styles[type]}`.trim()}
      role={type === "error" ? "alert" : "status"}
      aria-live={type === "error" ? "assertive" : "polite"}
    >
      <span className={styles.icon}>
        {type === "success" ? <CheckIcon width={16} height={16} /> : null}
        {type === "error" ? <ErrorIcon width={16} height={16} /> : null}
        {type === "info" ? <InfoIcon width={16} height={16} /> : null}
      </span>
      <span className={styles.text}>{message}</span>
    </div>
  );
}

.message {
  position: fixed;
  bottom: 2rem;
  right: 2rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 1rem 1.5rem;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: 6px;
  box-shadow: 0 4px 12px rgba(1, 6, 7, 0.15);
  font-size: 0.9rem;
  animation: slideIn 0.3s ease-out;
  z-index: 1000;
}

@keyframes slideIn {
  from {
    transform: translateX(100%);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

.icon {
  display: inline-flex;
}

.text {
  color: var(--text-primary);
}

.success {
  border-color: var(--success);
}

.success .icon {
  color: var(--success);
}

.error {
  border-color: var(--danger);
}

.error .icon {
  color: var(--danger);
}

.info {
  border-color: var(--info);
}

.info .icon {
  color: var(--info);
}
